import { useState } from 'react';
import { ArrowRight, ChevronRight } from 'lucide-react';
import { Btn } from './ds';

const SAMPLES = [
  'Client has ₹5 lakh to invest in Reliance Industries, 3-year horizon',
  'Should my client buy TCS at current levels?',
  'Client holding HDFC Bank at a loss — hold or exit?',
  'Compare Infosys vs Wipro for a 2-year horizon',
  'Is this a good time to enter a Nifty 50 index fund?',
  'Outlook on Adani Ports — fundamentals and risks',
];

export default function TextTab({ onAnalyze, loading }) {
  const [q, setQ] = useState('');
  const send = () => { if (q.trim()) onAnalyze(q.trim()); };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>

      {/* Query input */}
      <div>
        <label style={{ fontSize: 11, fontWeight: 600, color: 'var(--ink-3)', letterSpacing: '0.08em', textTransform: 'uppercase', display: 'block', marginBottom: 8 }}>
          Client conversation or question
        </label>
        <textarea
          value={q}
          onChange={e => setQ(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter' && e.ctrlKey) send(); }}
          disabled={loading}
          rows={6}
          placeholder={"What is your client asking about?\n\nExample: \"My client has ₹5L ready. She's been watching Reliance for months and wants to know if now is the right entry point for a 3-year hold.\""}
          style={{
            width: '100%', padding: '14px 16px',
            border: '1px solid var(--rule-2)',
            borderRadius: 'var(--r-md)',
            background: loading ? 'var(--paper)' : 'var(--white)',
            fontSize: 13, color: 'var(--ink)', lineHeight: 1.75,
            fontFamily: 'var(--f-ui)', outline: 'none',
            transition: 'border-color 0.15s, box-shadow 0.15s',
          }}
          onFocus={e => {
            e.target.style.borderColor = 'var(--accent)';
            e.target.style.boxShadow = '0 0 0 3px var(--accent-bg)';
          }}
          onBlur={e => {
            e.target.style.borderColor = 'var(--rule-2)';
            e.target.style.boxShadow = 'none';
          }}
        />
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 10 }}>
          <span style={{ fontSize: 11.5, color: 'var(--ink-4)' }}>
            {q.length > 0 ? `${q.length} characters` : 'Ctrl + Enter to submit'}
          </span>
          <div style={{ display: 'flex', gap: 7 }}>
            {q && <Btn look='ghost' size='sm' onClick={() => setQ('')}>Clear</Btn>}
            <Btn look='fill' size='sm' disabled={loading || !q.trim()} onClick={send} Icon={ArrowRight}>
              {loading ? 'Analyzing…' : 'Analyze'}
            </Btn>
          </div>
        </div>
      </div>

      {/* Divider */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
        <div style={{ flex: 1, height: 1, background: 'var(--rule)' }} />
        <span style={{ fontSize: 10.5, color: 'var(--ink-5)', fontWeight: 600, letterSpacing: '0.06em', textTransform: 'uppercase' }}>
          or try one of these
        </span>
        <div style={{ flex: 1, height: 1, background: 'var(--rule)' }} />
      </div>

      {/* Sample queries */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
        {SAMPLES.map((text, i) => (
          <button
            key={i}
            disabled={loading}
            onClick={() => { setQ(text); onAnalyze(text); }}
            style={{
              display: 'flex', alignItems: 'center', gap: 10,
              padding: '9px 10px',
              background: 'transparent', border: 'none',
              borderRadius: 'var(--r)', cursor: 'pointer',
              fontFamily: 'var(--f-ui)', fontSize: 13, color: 'var(--ink-3)',
              textAlign: 'left', transition: 'all 0.1s',
              opacity: loading ? 0.4 : 1,
            }}
            onMouseEnter={e => {
              e.currentTarget.style.background = 'var(--white)';
              e.currentTarget.style.color = 'var(--ink)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.background = 'transparent';
              e.currentTarget.style.color = 'var(--ink-3)';
            }}
          >
            <ChevronRight size={12} strokeWidth={2.5} style={{ flexShrink: 0, opacity: 0.5 }} />
            <span style={{ flex: 1 }}>{text}</span>
            <span style={{ fontFamily: 'var(--f-data)', fontSize: 10, color: 'var(--ink-5)', flexShrink: 0 }}>
              {String(i + 1).padStart(2, '0')}
            </span>
          </button>
        ))}
      </div>
    </div>
  );
}
